use crate::registry::GainModelDefinition;
use crate::GainBackendKind;
use anyhow::Result;
use block_core::param::{
    bool_parameter, float_parameter, required_bool, required_f32,
    ModelParameterSchema, ParameterSet, ParameterUnit,
};
use block_core::{AudioChannelLayout, BlockProcessor, ModelAudioMode};

pub const MODEL_ID: &str = "lv2_invada_bad_tube_stereo";
pub const DISPLAY_NAME: &str = "Invada Tube Distortion (stereo)";
const BRAND: &str = "invada";

const PLUGIN_URI: &str = "http://invadarecords.com/plugins/lv2/tube/stereo";
const PLUGIN_DIR: &str = "invada-bad";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "inv_tube.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "inv_tube.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "inv_tube.dll";

// Port indices (from TTL)
const PORT_CTRL_BYPASS: usize = 0;
const PORT_CTRL_DRIVE: usize = 1;
const PORT_CTRL_DCOFFSET: usize = 2;
const PORT_CTRL_PHASE: usize = 3;
const PORT_CTRL_MIX: usize = 4;
const PORT_CTRL_METER_DRIVE: usize = 5;
const PORT_CTRL_METER_IN_L: usize = 6;
const PORT_CTRL_METER_OUT_L: usize = 7;
const PORT_AUDIO_IN_IN_L: usize = 8;
const PORT_AUDIO_OUT_OUT_L: usize = 9;
const PORT_CTRL_METER_IN_R: usize = 10;
const PORT_CTRL_METER_OUT_R: usize = 11;
const PORT_AUDIO_IN_IN_R: usize = 12;
const PORT_AUDIO_OUT_OUT_R: usize = 13;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_GAIN.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("drive", "Drive", None, Some(0.0), 0.0, 18.0, 0.1, ParameterUnit::Decibels),
            float_parameter("dcoffset", "DC Offset", None, Some(0.0), -1.0, 1.0, 0.01, ParameterUnit::None),
            bool_parameter("phase", "Tube Phase", None, Some(false)),
            float_parameter("mix", "Mix", None, Some(75.0), 0.0, 100.0, 1.0, ParameterUnit::Percent),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let drive = required_f32(params, "drive").map_err(anyhow::Error::msg)?;
    let dcoffset = required_f32(params, "dcoffset").map_err(anyhow::Error::msg)?;
    let phase = required_bool(params, "phase").map_err(anyhow::Error::msg)?;
    let mix = required_f32(params, "mix").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_DRIVE, drive),
        (PORT_CTRL_DCOFFSET, dcoffset),
        (PORT_CTRL_PHASE, if phase { 1.0 } else { 0.0 }),
        (PORT_CTRL_MIX, mix),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: GainModelDefinition = GainModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: GainBackendKind::Lv2, schema, build,
    validate, asset_summary,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};

fn validate(_params: &ParameterSet) -> Result<()> { Ok(()) }
fn asset_summary(_params: &ParameterSet) -> Result<String> { Ok(String::new()) }
